         Waveform = [linspace(0,DC,length(i1)) linspace(DC+d,Peak,length(i2)-length(i1)) linspace(Peak,0,length(i2))];
         Waveform = (Waveform / GainSP);
         %Waveform = [Waveform_IRM zeros(1,1400-Nramp)];
         Waveform_Volts = Waveform;

         % Scale to DAC counts
         % DAC counts (-32768 to 32767) -> (-10 to 10 Volts)
         Waveform = Waveform * 32767 / 10;
         Waveform = -1 * Waveform * 1.5;  % Not sure why it took 1.5 to make the output the same as the mini-IOC???
         Waveform = round(Waveform);
     end
 else
     Npts = length(Waveform);
     t = linspace(0, T, Npts);
     Waveform_Volts = Waveform * 10 * 32767 / 1.5;  % Why the factor of 1.5 scaling???
 end


 % Plot
 if DisplayFlag
     h = subplot(2,1,1);
     plot(t, Waveform_Volts);
     xlabel('Time [Seconds]');
     ylabel('[Volts]');
     title(sprintf('SF Waveform, %d Points in Table', Npts));

     h(2) = subplot(2,1,2);
     plot(t, Waveform);
     xlabel('Time [Seconds]');
     ylabel('[Counts]');

     linkaxes(h, 'x');
 end


